function AdminPanel({ config, setConfig, featured, setFeatured }) {
  const setNumber = (key) => (e) => {
    const v = Number(e.target.value || 0);
    setConfig(c => ({ ...c, [key]: isNaN(v) ? 0 : v }));
  };
  const label = { fontSize:"11px", color:text3, marginBottom:"6px" };
  const input = { width:"100%", background:bg1, border:`1px solid rgba(255,255,255,0.1)`, borderRadius:"8px", padding:"10px 12px", color:text1, fontSize:"13px", outline:"none" };
  const card = { ...S.dashCard, padding:"16px" };
  const [bulk, setBulk] = useState("");
  const [playlist, setPlaylist] = useState("");
  const [loading, setLoading] = useState(false);
  const apiMissing = !import.meta.env.VITE_YT_API_KEY;
  const parseIds = (s) => {
    const tokens = s.split(/[\s,]+/).filter(Boolean);
    const ids = [];
    const rx = /(?:v=|\/shorts\/|youtu\.be\/)([A-Za-z0-9_-]{6,})/;
    for (const t of tokens) {
      const m = t.match(rx);
      if (m) ids.push(m[1]);
      else if (/^[A-Za-z0-9_-]{6,}$/.test(t)) ids.push(t);
    }
    return Array.from(new Set(ids));
  };
  const buildFromIds = (ids) => {
    return ids.map((id, idx) => ({
      id: `yt-${id}`,
      title: `YouTube ${id}`,
      genre: "Web",
      duration: "--:--",
      views: 0,
      watchTime: 0,
      completion: 0,
      thumb: `https://img.youtube.com/vi/${id}/hqdefault.jpg`,
      hls: "#",
      youtubeId: id,
      description: "Imported from YouTube",
      producer: "YouTube",
      episode: `Item ${idx+1}`,
      year: new Date().getFullYear(),
    }));
  };
  const onReplaceFeatured = () => {
    const ids = parseIds(bulk);
    if (ids.length === 0) return;
    const items = buildFromIds(ids);
    setFeatured(items);
    try { localStorage.setItem("featured", JSON.stringify(items)); } catch (e) { void e; }
  };
  const onResetFeatured = () => {
    setFeatured(FEATURED);
    try { localStorage.removeItem("featured"); } catch (e) { void e; }
  };
  const parsePlaylistId = (s) => {
    const m = s.match(/[?&]list=([A-Za-z0-9_-]+)/) || s.match(/^PL[A-Za-z0-9_-]+$/);
    return m ? (m[1] || s) : s;
  };
  const onFetchPlaylist = async () => {
    if (apiMissing) return;
    const id = parsePlaylistId(playlist.trim());
    if (!id) return;
    setLoading(true);
    try {
      const items = await fetchPlaylistItems(id);
      setFeatured(items);
      try { localStorage.setItem("featured", JSON.stringify(items)); } catch (e) { void e; }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };
  return (
    <div style={{ padding:"16px" }}>
      <div style={{ display:"flex", alignItems:"center", gap:"10px", marginBottom:"16px" }}>
        <img src={LOGO_URI} alt="logo" style={{ width:"28px", height:"28px", borderRadius:"8px" }} />
        <div style={{ fontFamily:"'DM Sans', sans-serif", fontWeight:800, letterSpacing:"0.04em" }}>Admin Controls</div>
      </div>
      <div style={card}>
        <div style={{ fontSize:"10px", color:text3, letterSpacing:"0.14em", marginBottom:"10px" }}>PAYOUT SETTINGS</div>
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"12px" }}>
          <div>
            <div style={label}>Views per Star</div>
            <input type="number" min="1" value={config.viewsPerStar} onChange={setNumber("viewsPerStar")} style={input} />
          </div>
          <div>
            <div style={label}>Ad CPM (K per 1000)</div>
            <input type="number" min="0" value={config.adCPM} onChange={setNumber("adCPM")} style={input} />
          </div>
          <div>
            <div style={label}>PPV Price (K)</div>
            <input type="number" min="0" value={config.ppvPrice} onChange={setNumber("ppvPrice")} style={input} />
          </div>
          <div>
            <div style={label}>Royalty Share</div>
            <div style={{ ...input, display:"flex", alignItems:"center", justifyContent:"space-between" }}>
              <span>8%</span>
              <span style={{ fontSize:"11px", color:text3 }}>Fixed</span>
            </div>
          </div>
        </div>
      </div>
      <div style={card}>
        <div style={{ fontSize:"10px", color:text3, letterSpacing:"0.14em", marginBottom:"10px" }}>YOUTUBE PLAYLIST IMPORT</div>
        <div style={{ display:"grid", gridTemplateColumns:"1fr auto", gap:"8px", alignItems:"center", marginBottom:"10px" }}>
          <input
            placeholder="Playlist URL or ID"
            value={playlist}
            onChange={e=>setPlaylist(e.target.value)}
            style={input}
          />
          <button
            onClick={onFetchPlaylist}
            disabled={apiMissing || loading}
            style={{ background: apiMissing ? "rgba(255,255,255,0.06)" : "rgba(109,191,74,0.2)", border:`1px solid ${apiMissing ? "rgba(255,255,255,0.1)" : "rgba(109,191,74,0.6)"}`, color: apiMissing ? text3 : "#c8ffaa", padding:"10px 14px", borderRadius:"8px", fontWeight:800, cursor: apiMissing ? "not-allowed" : "pointer", fontSize:"12px" }}
          >{loading ? "Fetching..." : "Fetch Playlist"}</button>
        </div>
        {apiMissing && <div style={{ fontSize:"12px", color:text2, marginBottom:"10px" }}>Set VITE_YT_API_KEY to enable playlist import.</div>}
        <div style={{ fontSize:"11px", color:text3 }}>Example: https://www.youtube.com/playlist?list=PLsEKtBln2-kKJ1MhAlyE99746BbePzJas</div>
      </div>
      <div style={card}>
        <div style={{ fontSize:"10px", color:text3, letterSpacing:"0.14em", marginBottom:"10px" }}>PREVIEW</div>
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"10px" }}>
          {featured.slice(0,2).map(v => {
            const adGross = (v.views/1000) * config.adCPM;
            const ppvGross = 0;
            const payout = Math.round((adGross + ppvGross) * 0.08);
            const stars = Math.floor(v.views / config.viewsPerStar);
            return (
              <div key={v.id} style={{ background:bg1, border:`1px solid rgba(255,255,255,0.06)`, borderRadius:"10px", padding:"10px" }}>
                <div style={{ fontSize:"12px", fontWeight:700, marginBottom:"6px" }}>{v.title}</div>
                <div style={{ fontSize:"11px", color:text3, marginBottom:"6px" }}>👁 {fmt.views(v.views)} · ⭐ {stars}</div>
                <div style={{ display:"flex", justifyContent:"space-between", fontSize:"12px" }}>
                  <span>K{adGross.toFixed(0)} gross</span>
                  <span style={{ color:green, fontWeight:700 }}>K{payout} royalty</span>
                </div>
              </div>
            );
          })}
        </div>
      </div>
      <div style={card}>
        <div style={{ fontSize:"10px", color:text3, letterSpacing:"0.14em", marginBottom:"10px" }}>FEATURED IMPORT</div>
        <div style={{ fontSize:"12px", color:text2, marginBottom:"8px" }}>Paste YouTube video URLs or IDs (one per line). We'll build thumbnails and play via YouTube.</div>
        <textarea value={bulk} onChange={e=>setBulk(e.target.value)} style={{ width:"100%", minHeight:"120px", background:bg1, border:`1px solid rgba(255,255,255,0.1)`, borderRadius:"8px", padding:"10px 12px", color:text1, fontSize:"13px", outline:"none", marginBottom:"10px" }} />
        <div style={{ display:"flex", gap:"8px" }}>
          <button onClick={onReplaceFeatured} style={{ background:"rgba(109,191,74,0.2)", border:`1px solid rgba(109,191,74,0.6)`, color:"#c8ffaa", padding:"10px 14px", borderRadius:"8px", fontWeight:800, cursor:"pointer", fontSize:"12px" }}>Replace Featured</button>
          <button onClick={onResetFeatured} style={{ background:"transparent", border:`1px solid rgba(255,255,255,0.1)`, color:text2, padding:"10px 14px", borderRadius:"8px", cursor:"pointer", fontSize:"12px" }}>Reset to Defaults</button>
        </div>
      </div>
    </div>
  );
}

