function UploadView({ onBack, featured, setFeatured, goTo }) {
  const [file, setFile] = useState(null);
  const [progress, setProgress] = useState(0);
  const [status, setStatus] = useState("");
  // Cloudinary (preferred free path)
  const cloudName = import.meta.env.VITE_CLOUDINARY_CLOUD_NAME;
  const cloudPreset = import.meta.env.VITE_CLOUDINARY_UPLOAD_PRESET;
  const hasCloud = !!cloudName && !!cloudPreset;
  // Firebase (fallback)
  const cfg = {
    apiKey: import.meta.env.VITE_FB_API_KEY,
    authDomain: import.meta.env.VITE_FB_AUTH_DOMAIN,
    projectId: import.meta.env.VITE_FB_PROJECT_ID,
    storageBucket: import.meta.env.VITE_FB_STORAGE_BUCKET,
    appId: import.meta.env.VITE_FB_APP_ID,
  };
  const hasFB = !!cfg.apiKey && !!cfg.storageBucket && !!cfg.projectId;
  let app;
  if (hasFB) app = getApps().length ? getApps()[0] : initializeApp(cfg);
  // Supabase (optional)
  const supaUrl = import.meta.env.VITE_SUPABASE_URL;
  const supaAnon = import.meta.env.VITE_SUPABASE_ANON_KEY;
  const hasSupa = !!supaUrl && !!supaAnon;
  const supabase = hasSupa ? createSupabaseClient(supaUrl, supaAnon) : null;

  const addToFeatured = (url) => {
    const item = {
      id: `mp-${Date.now()}`,
      title: file.name,
      genre: "User Upload",
      duration: "--:--",
      views: 0,
      watchTime: 0,
      completion: 0,
      thumb: "",
      hls: "#",
      mp4Url: url,
      description: "User uploaded video",
      producer: "You",
      episode: "Upload",
      year: new Date().getFullYear(),
    };
    setFeatured([item, ...featured]);
    setStatus("Done");
    goTo(item.id);
  };

  const startUpload = async () => {
    if (!file) return;
    // 1) Cloudinary unsigned upload
    if (hasCloud) {
      setStatus("Uploading to Cloudinary…");
      const endpoint = `https://api.cloudinary.com/v1_1/${cloudName}/auto/upload`;
      const fd = new FormData();
      fd.append("file", file);
      fd.append("upload_preset", cloudPreset);
      fd.append("folder", "tsopano");
      const xhr = new XMLHttpRequest();
      xhr.upload.onprogress = (e) => {
        if (e.lengthComputable) setProgress(Math.round((e.loaded / e.total) * 100));
      };
      xhr.onreadystatechange = () => {
        if (xhr.readyState === 4) {
          try {
            const res = JSON.parse(xhr.responseText || "{}");
            if (xhr.status >= 200 && xhr.status < 300 && res.secure_url) {
              addToFeatured(res.secure_url);
            } else {
              setStatus("Upload failed");
            }
          } catch {
            setStatus("Upload failed");
          }
        }
      };
      xhr.open("POST", endpoint);
      xhr.send(fd);
      return;
    }
    // 2) Supabase (if configured)
    if (hasSupa && supabase) {
      setStatus("Uploading to Supabase…");
      const path = `uploads/${Date.now()}-${file.name}`;
      const { error } = await supabase.storage.from("videos").upload(path, file, { contentType: file.type });
      if (error) { setStatus("Upload failed"); return; }
      const { data } = supabase.storage.from("videos").getPublicUrl(path);
      addToFeatured(data.publicUrl);
      return;
    }
    // 3) Firebase fallback (if configured)
    if (hasFB && app) {
      setStatus("Signing in…");
      const auth = getAuth(app);
      await signInAnonymously(auth).catch(()=>{});
      const storage = getStorage(app);
      const path = `uploads/${Date.now()}-${file.name}`;
      const ref = storageRef(storage, path);
      setStatus("Uploading…");
      const task = uploadBytesResumable(ref, file);
      task.on("state_changed", snap => {
        const pct = Math.round((snap.bytesTransferred / snap.totalBytes) * 100);
        setProgress(pct);
      }, () => setStatus("Upload failed"), async () => {
        const url = await getDownloadURL(task.snapshot.ref);
        addToFeatured(url);
      });
      return;
    }
    setStatus("No storage configured");
  };
  return (
    <div style={{ padding:"16px" }}>
      <div style={{ display:"flex", alignItems:"center", gap:"10px", marginBottom:"16px" }}>
        <button onClick={onBack} style={{ background:"none", border:"none", color:text1, fontSize:"22px", cursor:"pointer" }}>←</button>
        <span style={{ fontFamily:"'DM Sans', sans-serif", fontWeight:700, fontSize:"16px" }}>Upload a Video</span>
      </div>
      {(!hasCloud && !hasSupa && !hasFB) && (
        <div style={{ background:bg1, border:`1px solid rgba(255,255,255,0.06)`, borderRadius:"12px", padding:"12px", fontSize:"12px", color:text2, marginBottom:"12px" }}>
          Tip: For online uploads, add one of these (free) and redeploy:<br/>
          • Cloudinary (recommended): VITE_CLOUDINARY_CLOUD_NAME, VITE_CLOUDINARY_UPLOAD_PRESET<br/>
          • Firebase (fallback): VITE_FB_API_KEY, VITE_FB_AUTH_DOMAIN, VITE_FB_PROJECT_ID, VITE_FB_STORAGE_BUCKET, VITE_FB_APP_ID<br/>
          Without these, the app will preview locally only (not persisted after refresh).
        </div>
      )}
      <div style={{ background:bg1, border:`1px solid rgba(255,255,255,0.06)`, borderRadius:"12px", padding:"16px" }}>
        <input type="file" accept="video/*" onChange={e=>setFile(e.target.files?.[0]||null)} style={{ marginBottom:"12px" }} />
        <button
          onClick={async () => {
            if (!file) return;
            if (!hasCloud && !hasSupa && !hasFB) {
              // Local preview fallback (non-persistent)
              setStatus("Local preview");
              const url = URL.createObjectURL(file);
              addToFeatured(url);
              return;
            }
            await startUpload();
          }}
          disabled={!file}
          style={{ background:"rgba(109,191,74,0.2)", border:`1.5px solid rgba(109,191,74,0.6)`, color:"#c8ffaa", padding:"10px 16px", borderRadius:"8px", fontWeight:800, cursor:file?"pointer":"not-allowed", fontSize:"13px" }}
        >
          Start Upload
        </button>
        {status && <div style={{ marginTop:"10px", fontSize:"12px", color:text2 }}>{status} {progress ? `· ${progress}%` : ""}</div>}
      </div>
    </div>
  );
}

// ─── APP ROOT ───────────────────────────────────────────────────────────────
export default function TsopanoTV() {
  const [selfTapes, setSelfTapes] = useState(SELF_TAPES);
  const [featured, setFeatured] = useState(() => {
    try {
      const s = localStorage.getItem("featured");
      return s ? JSON.parse(s) : FEATURED;
    } catch { return FEATURED; }
  });
  const [config, setConfig] = useState({ viewsPerStar: 2000, adCPM: 15, ppvPrice: 10 });
  const navigate = useNavigate();
  const location = useLocation();
  const calcPayout = ({ views, paidViews = 0 }) => {
    const adGross = (views / 1000) * config.adCPM;
    const ppvGross = paidViews * config.ppvPrice;
    const gross = adGross + ppvGross;
    return Math.round(gross * 0.08);
  };
  const onVideoSelect = (v) => { navigate(`/video/${v.id}`); };
  const onSelfTapeSelect = (t) => { navigate(`/tape/${t.id}`); };
  const onPublishTape = ({ title, submitter, thumb }) => {
    const newTape = { id:`user-${Date.now()}`, title, stars:0, views:0, submitter, thumb, sceneRef:"User Submission" };
    setSelfTapes(tapes => [newTape, ...tapes]);
  };

  useEffect(() => {
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = "https://fonts.googleapis.com/css2?family=DM+Sans:wght@300;400;500;600&display=swap";
    document.head.appendChild(link);
  }, []);
  useEffect(() => {
    try { localStorage.setItem("featured", JSON.stringify(featured)); } catch (e) { void e; }
  }, [featured]);
  useEffect(() => {
    const autoId = import.meta.env.VITE_YT_PLAYLIST_ID;
    const hasKey = !!import.meta.env.VITE_YT_API_KEY;
    if (!hasKey || !autoId) return;
    (async () => {
      try {
        const [meta, items] = await Promise.all([
          fetchPlaylistMeta(autoId).catch(()=>null),
          fetchPlaylistItems(autoId).catch(()=>[]),
        ]);
        const first = items[0];
        const card = {
          id: `ytpl-${autoId}`,
          title: meta?.title || "YouTube Playlist",
          genre: "Web",
          duration: `${meta?.count || items.length} videos`,
          views: 0,
          watchTime: 0,
          completion: 0,
          thumb: meta?.thumb || first?.thumb || "",
          hls: "#",
          youtubePlaylistId: autoId,
          youtubeId: first?.youtubeId || "",
          description: meta?.description || "Imported playlist",
          producer: "YouTube",
          episode: "Playlist",
          year: new Date().getFullYear(),
        };
        setFeatured([card]);
        try { localStorage.setItem("featured", JSON.stringify([card])); } catch (e) { void e; }
      } catch (e) {
        console.error("Auto playlist import failed", e);
      }
    })();
  }, []);

  return (
    <div style={S.app}>
      <nav style={S.nav}>
        {/* 3D orange-black gradient texture background */}
        <div style={{
          position:"absolute", inset:0,
          background:"radial-gradient(ellipse at 30% 50%, rgba(200,90,0,0.55) 0%, rgba(140,50,0,0.3) 35%, rgba(20,20,20,0.0) 70%), radial-gradient(ellipse at 80% 20%, rgba(255,140,0,0.25) 0%, transparent 55%), linear-gradient(160deg, #1a0d00 0%, #0e0e0e 40%, #1a1a1a 70%, #111 100%)",
          zIndex:0,
        }} />
        {/* Subtle noise/grain texture overlay */}
        <div style={{ position:"absolute", inset:0, zIndex:1, backgroundImage:"repeating-linear-gradient(45deg, rgba(255,255,255,0.018) 0px, rgba(255,255,255,0.018) 1px, transparent 1px, transparent 9px)" }} />
        {/* Subtle 3D inner shadow at bottom */}
        <div style={{ position:"absolute", bottom:0, left:0, right:0, height:"4px", background:"linear-gradient(to bottom, transparent, rgba(255,100,0,0.2))", zIndex:1 }} />
        {/* Content */}
        <div style={{ position:"relative", zIndex:2, display:"flex", flexDirection:"column", alignItems:"center", padding:"18px 16px 14px" }}>
          <img src={LOGO_URI} alt="Tsopano TV" style={S.logoImg} />
          <div style={{ marginTop:"10px", textAlign:"center" }}>
            <BrandText size={36} />
          </div>
          <div style={{ marginTop:"5px", textAlign:"center" }}>
            <Tagline size={18} />
          </div>
        </div>
        {/* Login button top-right */}
        <button onClick={() => navigate("/login")} style={{ ...S.loginBtn, position:"absolute", top:"12px", right:"14px", zIndex:3 }}>LOG IN</button>
      </nav>

      <div style={{ paddingBottom:"72px" }}>
        <Routes>
          <Route path="/" element={<HomePage featured={featured} onVideoSelect={onVideoSelect} onSelfTapeSelect={onSelfTapeSelect} viewsPerStar={config.viewsPerStar} selfTapes={selfTapes} />} />
          <Route path="/dashboard" element={<ProducerDashboard calcPayout={calcPayout} />} />
          <Route path="/arch" element={<ArchView />} />
          <Route path="/admin" element={<AdminPanel config={config} setConfig={setConfig} featured={featured} setFeatured={setFeatured} />} />
          <Route path="/upload" element={<UploadView onBack={() => navigate("/")} featured={featured} setFeatured={setFeatured} goTo={(id)=>navigate(`/video/${id}`)} />} />
          <Route path="/login" element={<LoginView onBack={() => navigate("/")} />} />
          <Route path="/video/:id" element={<VideoScreen videos={featured} onBack={() => navigate("/")} />} />
          <Route path="/tape/:id" element={<TapeScreen onBack={() => navigate("/")} viewsPerStar={config.viewsPerStar} calcPayout={calcPayout} onPublish={onPublishTape} />} />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </div>

      <nav style={S.bottomNav}>
        {[
          { id:"home",      icon:"home",      label:"Home" },
          { id:"dashboard", icon:"dashboard", label:"Dashboard" },
          { id:"upload",    icon:"upload",    label:"Upload" },
          { id:"arch",      icon:"arch",      label:"Architecture" },
          { id:"admin",     icon:"admin",     label:"Admin" },
        ].map(({ id, icon, label }) => (
          <button key={id} style={S.navTab} onClick={() => { navigate(id === "home" ? "/" : `/${id}`); }}>
            <span style={{ fontSize:"19px" }}>
              <Icon name={icon} size={19} color={(location.pathname === "/" && id==="home") || (location.pathname.startsWith(`/${id}`) && id!=="home") ? green : text3} />
            </span>
            <span style={(location.pathname === "/" && id==="home") || (location.pathname.startsWith(`/${id}`) && id!=="home") ? S.navTabLabelActive : S.navTabLabel}>{label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
}

function VideoScreen({ videos, onBack }) {
  const { id } = useParams();
  const v = (videos || []).find(x => x.id === id);
  if (!v) return <Navigate to="/" replace />;
  return <VideoPlayer video={v} onBack={onBack} />;
}

function TapeScreen({ onBack, viewsPerStar, calcPayout, onPublish }) {
  const { id } = useParams();
  const all = SELF_TAPES; // initial pool; user-added tapes appear on home but for deep link we keep to initial IDs
  const t = all.find(x => x.id === id) || null;
  if (!t) return <Navigate to="/" replace />;
  return <SelfTapePage tape={t} onBack={onBack} viewsPerStar={viewsPerStar} calcPayout={calcPayout} onPublish={onPublish} />;
}
